INSERT INTO `condition_generale` (`id`, `titre`, `contenu`, `slug`) VALUES
(1, 'Conditions générales', '<p>***Conditions Générales d\'Utilisation du site&nbsp;boopursal&nbsp;***</p><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p>Les présentes conditions générales d’utilisation du site Internet&nbsp;boopursal&nbsp;(ci-après le « Site ») ont pour objet de régir les droits et obligations de la Société&nbsp;\"7e-sky\"&nbsp;éditrice et propriétaire du site (ci-après «&nbsp;boopursal&nbsp;») et de l’utilisateur (ci-après l’« Utilisateur ») du Site dans le cadre des prestations de services fournies par le site&nbsp;www.boopursal.com. Par conséquence, toute utilisation, consultation du Site ou inscription sur le Site implique l’adhésion pleine et entière de l’Utilisateur aux présentes conditions générales d’utilisation.</p><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p>***ARTICLE 1 – Le concept***</p><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p>1.1. Le Site a pour objet principal la mise en relation de sociétés (les Acheteurs) préalablement inscrites sur le site souhaitant trouver des fournisseurs de leurs produits ou services, ces derniers (Les Fournisseurs) qui sont eux aussi préalablement inscrits sur le Site se disent capable de fournir le produit ou service demandé par l’acheteur dans les meilleures conditions. Les Acheteurs, les fournisseurs (Produit / service) ainsi que les sous-traitants sont ci- après dénommés les Utilisateurs ou individuellement l’Utilisateur.1.2. L\'enregistrement sur&nbsp;boopursal&nbsp;en tant que Fournisseur engage ce dernier une fois qu’il décide de participer à un Appel d’offre, à fournir le produit ou service pour lequel il s’est inscrit comme fournisseur.1.3. L\'enregistrement sur&nbsp;boopursal&nbsp;en tant qu’Acheteur engage ce dernier à ne pas lancer de fausse demande de prix, il s’engage à ce que ses demandes soient fondées sur un besoin réel et réalisable.</p><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p>***ARTICLE 2 – Du côté de l’utilisation du Site par les Acheteurs***</p><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p>2.1. Les Acheteurs sont obligés de créer un compte utilisateur contenant ses données d’identification, telles que demandées sur le Site (ci-après l’Identification).2.2. Tout Acheteur est tenu de fournir, lors de son inscription sur le Site une Identification exacte, complète et à jour permettant de le contacter.2.3.&nbsp;\"7e-sky\"&nbsp;ne possède pas les moyens de contrôler l’exactitude des informations fournies par l’Acheteur lors de son inscription ni les autres informations éventuellement communiquées ultérieurement par l’Acheteur et disponibles sur le Site.2.4.&nbsp;\"7e-sky\"&nbsp;se réserve le droit de rendre \"Invalide\" tous compte d’acheteur s’il s’avère en non-conformité avec la déontologie du site web www.boopursal.com. Tout plan ou dessins accompagnant les appels d\'offre des acheteurs, sera automatiquement modifier voir supprimé s’ils dissimulent ou mentionnent en quoique ce soit une indication ou un signe pouvant permettre d\'identifier la provenance de l\'appel d\'offre.2.5. L’Acheteur s’engage à mettre à jour l’Identification le concernant en cas de modification de cette dernière.2.6.&nbsp;\"7e-sky\"&nbsp;à travers son site web&nbsp;boopursal&nbsp;se réserve le droit de diffuser les coordonnées de tout utilisateur de ce site ceux des Acheteurs au divers Fournisseurs, et ceux des Fournisseurs aux divers Acheteurs ou à d’autres utilisateurs2.7&nbsp;\"7e-sky\"&nbsp;ne saurait en conséquence être tenue pour responsable des inconvénients et des inexactitudes qui pourraient être transmises de façon délibérée ou par erreur par les utilisateurs (Acheteur / Fournisseur).2.8. L’acheteur s’engage à diffuser ses Appels d’Offres avec comme but de réaliser des transactions d\'achat potentielles, et à ne pas soumettre des Appels d\'Offres avec comme objectif de consulter et/ou comparer les prix ou propositions de ses propres concurrents.</p><p>&nbsp;</p><p>***ARTICLE 3 - Du côté de l’utilisation du Site par les Fournisseurs***</p><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p>3.1. L’accès au Site et son utilisation par le fournisseur est totalement gratuite sauf quand ce dernier est intéressé par un appel d’offre et veux voir les coordonnées de celui qui l’a lancé, néanmoins ce dernier est obligé de créer un compte utilisateur contenant ses données d’identification, telles que demandées sur le Site (ci-après l’Identification).3.2. Tout Fournisseur est tenu de fournir, lors de son inscription sur le Site, une Identification exacte, complète et à jour permettant de le contacter.3.3.&nbsp;\"7e-sky\"&nbsp;ne possède pas les moyens de contrôler l’exactitude des informations fournies par le Fournisseur lors de son inscription ni les autres informations éventuellement communiquées ultérieurement par le Fournisseur et disponibles sur le Site.3.4. Si lors de la consultation ou de l’utilisation du Site, le Fournisseur constate que l’Identification fournie par un autre Utilisateur est inexacte, le Fournisseur pourra le signaler en adressant un email à administrateur@boopursal.com3.5.&nbsp;\"7e-sky\"&nbsp;à travers son site web&nbsp;boopursal&nbsp;se réserve le droit de diffuser les coordonnées de tout utilisateur de ce site, ceux des Acheteurs au divers Fournisseurs, et ceux des Fournisseurs au divers Acheteurs ou à d’autres utilisateurs3.6.&nbsp;\"7e-sky\"&nbsp;ne saurait en conséquence être tenue pour responsable des inconvénients et des inexactitudes qui pourraient être transmise de façon délibérée ou par erreur par les utilisateurs (Acheteur / Fournisseur).</p><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p>***ARTICLE 4 – Règles de Paiement***</p><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p>4.1. Les jetons, packs, les bannières publicitaires et les campagnes publicitaires peuvent être vendues séparément, ou ensemble cela dépendra des clients et de leurs souhaits.4.2.&nbsp;\"7e-sky\"&nbsp;se réserve le droit de modifier à tout moment ses tarifs.4.3. Le règlement n’est pris en compte qu’une fois que notre compte bancaire soit crédité du montant figurant dans la facture correspondant à cet achat. Le paiement ne peut en aucun cas et sous aucune condition être remboursé. Les Packs Crédits ne sont pas transférables entre Fournisseur ou d’un Utilisateur à un autre.</p><p>&nbsp;</p><p>***ARTICLE 5 - Confidentialité des Données***</p><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p>5.1. L’Utilisateur s’engage à respecter les droits de propriété intellectuelle liés à toutes informations auxquelles il aura accès dans le cadre de l\'utilisation du site&nbsp;boopursal5.2. Tout Fournisseur s’engage à conserver confidentielles et à faire conserver confidentielles par son personnel, toutes les données auxquelles il a accès dans le cadre de l’utilisation du Site, sauf accord écrit de l’Acheteur pour divulguer ces données.5.3. Le Fournisseur s’interdit, sauf accord préalable de&nbsp;\"7e-sky\", et quel que soit le résultat de la mise en relation effectuée par l’intermédiaire du site&nbsp;boopursal&nbsp;de :- reproduire les données à d’autres fins que l’étude de l’offre de l’Acheteur,- vendre les données directement ou indirectement.</p><p>&nbsp;</p><p>***ARTICLE 6 - Blocage ou suppression du compte de l’Utilisateur***</p><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p>6.&nbsp;\"7e-sky\"&nbsp;se réserve le droit de bloquer ou de supprimer, à tout moment et sans préavis, le compte d’un Utilisateur, Acheteur, Fournisseur ou Société de service, sans avoir à s’en justifier, en cas de violation de tout ou partie des présentes conditions générales et/ou en cas d’inactivité du compte de l’Utilisateur pendant une durée de 12 mois. &nbsp;</p><p>&nbsp;</p><p>***ARTICLE 7 – Garanties***</p><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p>7.1. Les données figurant dans la base de données de&nbsp;www.boopursal.com&nbsp;sont déclaratives et fournies par les Utilisateurs, tiers par rapport à&nbsp;\"7e-sky\". Dès lors&nbsp;\"7e-sky\"&nbsp;ne garantit ni l’exactitude, ni la fiabilité des données communiquées par les Utilisateurs ni la solvabilité de ces derniers et ne peut en aucun cas en être tenue pour responsable.7.2.&nbsp;\"7e-sky\"&nbsp;ne pourra encourir une quelconque responsabilité en cas d’utilisation des Identifications non conformes à l’objet du service ou du fait des résultats qui pourraient être obtenus par l\'usage des Identifications.7.3.&nbsp;\"7e-sky\"&nbsp;est, et demeure, un tiers par rapport aux Utilisateurs. Dès lors, la responsabilité de son site&nbsp;www.boopursal.com&nbsp;ne pourra pas être engagée du fait d’inexécutions contractuelles ou de mauvaise exécution des contrats conclus entre Utilisateurs.7.4. La communication des plans du produit qu’il souhaite faire fabriquer est exposée aux risques et périls de l’Acheteur.7.5. Lors de la consultation du Site, l’Utilisateur peut, par l’usage des liens hypertextes mis en place par www.boopursal, accéder à d’autres sites Internet ou serveurs partenaires sur lesquels&nbsp;www.boopursal.com&nbsp;n’exerce aucun contrôle.Les sites Internet cibles étant susceptibles d’évoluer librement sans l’intervention ou l’autorisation de&nbsp;\"7e-sky\", l’Utilisateur reconnaît expressément que la responsabilité de&nbsp;\"7e-sky\"&nbsp;résultant du contenu des sites Internet cibles est exclue.7.6. Tout accord conclu par un Utilisateur avec des partenaires sur le site web www.boopursal se fait sous sa seule responsabilité, sans que la responsabilité de&nbsp;\"7e-sky\"&nbsp;ne puisse être engagée pour des raisons quelconques.</p><p>&nbsp;</p><p>***Article 8 - Droits de propriété intellectuelle***</p><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p>8.1. La marque&nbsp;«boopursal»&nbsp;et les noms de domaine&nbsp;boopursal.com, boopursal.fr, boopursal.ma,&nbsp;sont la propriété de&nbsp;\"7e-sky\".&nbsp;Toute utilisation du nom&nbsp;boopursal&nbsp;est interdite sans l’autorisation préalable et écrite de&nbsp;\"7e-sky\".8.2. Ce site et son contenu sont protégés, au sens du Code de la propriété intellectuelle, en particulier par les droits d\'auteur et de marques.8.3. En application du Code de la Propriété Intellectuelle et, plus généralement, des traités et accords internationaux comportant des dispositions relatives à la protection des droits d\'auteurs, l’Utilisateur s’interdit de reproduire même partiellement, vendre, distribuer, émettre, diffuser, adapter, modifier, publier, communiquer intégralement ou partiellement, sous quelque forme que ce soit la présentation ou l\'organisation du Site sans autorisation préalable et écrite de&nbsp;\"7e-sky\"</p><p>&nbsp;</p><p>8.4. Toute violation des droits et obligations ci-dessus énumérés constituerait une contrefaçon des droits de propriété intellectuelle de&nbsp;\"7e-sky\".</p><p>&nbsp;</p><p>***ARTICLE 9 - Accès au Site et modifications sur&nbsp;boopursal***</p><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p>9.1. L\'accès à tout ou partie du Site pourra être suspendu ou supprimé sur simple décision de&nbsp;\"7e-sky\"&nbsp;en cas de force majeure, de difficultés informatiques ou techniques, de difficultés liées à la structure des réseaux de télécommunications, de blocage des réseaux de télécommunications, de grève, d’état d’urgence national ou local, d’intempéries sans que cette liste ne soit exhaustive.9.2. De même, l\'accès au Site pourra être interrompu pour des raisons de maintenance.9.3.&nbsp;\"7e-sky\"&nbsp;se réserve le droit de modifier ou de faire évoluer à tout moment, les fenêtres du Site&nbsp;boopursal, ses fonctionnalités, les services, leur prix ou les conditions d\'utilisation qui lui sont applicables, et cela sans notification préalable d\'aucune sorte et sans que l’Utilisateur puisse invoquer un quelconque préjudice.</p><p>&nbsp;</p><p>***ARTICLE 10 - Données personnelles***</p><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p>10.1. Données personnelles10.1.1.&nbsp;\"7e-sky\"&nbsp;peut collecter et enregistrer des informations relatives à l’Utilisateur, personne physique ou morale, constituant des données à caractère personnel. Ces données sont enregistrées dans une base de données internes.10.1.2.&nbsp;\"7e-sky\"&nbsp;à travers son site web&nbsp;www.boopursal.com&nbsp;se réserve le droit de commercialiser les coordonnées téléphoniques, postales et/ou électroniques collectées auprès des Utilisateurs dans le cadre de ses services pour des opérations de mailing ciblées et d’envoi d’Alerte. Toutefois,&nbsp;\"7e-sky\"&nbsp;ne garantit pas la fiabilité et l’exactitude des données recueillies et ne peut dès lors engager une quelconque responsabilité en cas de non délivrance des envois adressés.10.1.3. Lors de son inscription, l’Utilisateur pourra s’opposer à la communication à des tiers et à l’utilisation par&nbsp;\"7e-sky\"&nbsp;de ses coordonnées.10.2. Les cookies10.2.1. Dans le cadre de la consultation ou de l’utilisation du Site,&nbsp;www.boopursal.com&nbsp;peut conserver certaines données concernant l’Utilisateur, pour les besoins du bon fonctionnement des services proposés ainsi qu’à des fins statistiques.10.2.2. L\'activation de cette fonction n\'est pas nécessaire pour visiter le Site.10.3. Autres données de connexion Lors de toute consultation du Site,&nbsp;www.boopursal.com&nbsp;collecte certaines données concernant l’Utilisateur, à savoir l’adresse IP, la date et la durée de sa visite et le matériel technique utilisé (système d\'exploitation, navigateur…). Ces informations qui sont rendues anonymes, ne sont collectées sur le serveur de&nbsp;www.boopursal.com&nbsp;et utilisées qu’à des fins statistiques.</p><p>&nbsp;</p><p>***ARTICLE 11 - Défauts de paiements***</p><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p>11. En cas de défaut ou de litige nés du paiement par un Utilisateur des services proposés par&nbsp;boopursal, avec l’aide de ses partenaires financiers,&nbsp;\"7e-sky\"&nbsp;se réserve le droit à effectuer toutes démarches ou enquêtes nécessaires à la récupération de sa créance.</p><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p>***ARTICLE 12 - Loi applicable et compétence***</p><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p>12.1. Les présentes conditions générales d’utilisation et tout contrat conclu en vertu des présentes sont soumis au droit Marocain.12.2. Tout litige relatif à la validité, à l’interprétation et/ou exécution des présentes et de tout contrat est soumis à la compétence des Tribunaux de Commerce de Casablanca – Maroc.12.3. Malgré les traductions des présentes conditions générales en anglais, allemand, et autres langues qui pourraient être proposées ultérieurement, l’Utilisateur reconnaît que seule la version en langue française fera foi entre lui et&nbsp;\"7e-sky\".</p><p>&nbsp;</p><p>&nbsp;</p>', 'conditions-generales'),
(2, 'Facturation', '<p>Contactez le département financier à propos de la facturation.<br><br><strong>Téléphone</strong> : +212-522.36.57.97.<br><strong>Fax</strong> : +212-522.36.57.95.<br><strong>Email</strong>: <a href=\"mailto:adherent@boopursal.com\">adherent@boopursal.com</a></p><p><strong>Coordonnées bancaires pour régler vos factures</strong><br><br><br><strong>Par virement bancaire Au :</strong><br><br><strong>7e-Sky</strong>&nbsp;<br>ATTIJARIWAFA BANK<br>CENTRE D\'AFFAIRE CASA PORTE D\'ANFA<br>Casablanca, Maroc<br><br><strong>Numéro du compte Bancaire</strong> : 007 780 0004095000002798 03</p>', 'facturation');
