(11, 773, 'BOUZOUBAA Karim', '+212667066481', 'k.bouzoubaa@parebriseexpress.ma', 'As part of the expansion of our distribution activity, Kartner Auto, a leading player in the automotive sector in Morocco, is seeking a supplier of AdBlue (EcoBlue) to supply our network of service centers and our fleet customers. We are looking for a partnership with a manufacturer capable of providing us with a stable supply, compliant with ISO 22241 and VDA standards, with the ability to customize packaging with our branding. We would also like to know the expected delivery time. The estimated volume is 600 tons per year, with monthly supply. The packaging formats are mostly IBCs of 1000 liters, and we would like to receive a CIF offer for the port of Casablanca.\nWe invite you to submit an offer if you can meet our requirements in terms of costs, quality, and logistics.\nIf you have any questions or need further information, please do not hesitate to contact me. We look forward to receiving your proposal soon.', '2024-10-17 23:10:37', '2024-11-02 18:49:54', 1, 0, NULL, 0),
(12, 750, 'EL JARRAY ABDELBASSET', '+212706862679', 'eljarray.a824@ucd.ac.ma', 'Bonjour madame\n je suis un Ã©tudiant de 3Ã¨me annÃ©e Ensa en filiÃ¨re de cybersÃ©curitÃ© et confiance numÃ©rique. Et je cherche un stage d\'initiation pour 1 mois dans votre Ã©tablissement.\nCordialement,\n[EL JARRAY ABDELBASSET]\n[eljarray.a824@ucd.ac.ma]https://www.dropbox.com/scl/fi/n9o3whzv03rdprlemj46l/Mon_cv.pdf?rlkey=wj4opfxqaiz2mb2dgtfugw8th&st=hk09e2dc&dl=0', '2025-07-06 00:19:34', NULL, 0, 0, NULL, 1),
(13, 760, 'brahim chatir', '+212649612354', 'b.chatir@gamutec.com', 'demande facture ste GAMUTEC / CHQ°6692858 / MAOBAG 34 200', '2025-08-12 11:47:07', '2025-10-08 12:39:45', 1, 0, NULL, 0),
(14, 760, 'Consectetur ab labor', '+212666112244', 'bydikolery@mailinator.com', 'Quis ut ullam dolore', '2026-01-16 15:04:17', NULL, 0, 0, NULL, 0),
(15, 1088, 'Keval ', '+916351123501', 'info@aaravyaspaces.com', 'We manufacture Venner Door and Teak wood Frame in India . We are ready to export our doors and Frames at indian Prices which are very competitive for your country . If you have a specific BOQ (Bill of Quantities) for any upcoming project, I’d be happy to prepare a cost-comparison for you.', '2026-03-03 11:32:20', NULL, 0, 0, NULL, 0);
