(765, 44, 117, 'Hongda Tea Factory', 'M.', NULL, '', 'http://en.hndtea.com/', 'Hongda Tea Co.,Ltd est une usine professionnelle de la production et exportation en gros du thé verts de Chine comme matière première ( 41022AAAAAA/41022AAA/41022/4011/9371; 3505AAAAA/3505AAA/3505A/3505B... ) depuis 1990s, située à Hunan en Chine.\n\nGrâce aux savoir-faire et expérience raffinés, nous satisfaisons aux besoins de nos partenaires avec une riche gamme de produits naturels et certifiés, en qualités sur-mesure sous libre type de partenariat. Qualités stablisées dont la capacité de production jusqu\'à 1200 tonnes par mois.\n\nContactez M.Han au Tel/WhatsApp+8617352820448 ou par courrier électrique han@hndtea.com.\nSite Web: www.hndtea.com', 2, 'hongda-tea-factory', 1, 130, 'hongda tea factory', 3, 1, 'F-76549b2', NULL, NULL, NULL, NULL);
INSERT INTO `fournisseur` (`id`, `pays_id`, `ville_id`, `societe`, `civilite`, `ice`, `fix`, `website`, `description`, `currency_id`, `slug`, `phone_vu`, `visite`, `societe_lower`, `step`, `is_complet`, `code_client`, `autre_ville`, `autre_categories`, `autre_currency`, `parent`) VALUES
(766, 144, 1, 'NRS groupe', 'M.', '002526170000027', '+212603124061', '', 'Qui sommes-nous ?\n\nNRS groupe est spécialisée dans la fourniture de services aux particuliers, professionnels et des collectivités. Nous opérons dans le domaine de la propreté, l’hygiène 3D (Désinsectisation, Dératisation, Désinfection), sécurité électronique, gardiennage, jardinage et nettoyage.\n\nPour répondre aux attentes de ses clients dans un secteur où la confiance et l’efficacité sont les maîtres mots, NRS groupe cherche à aller plus loin pour apporter les solutions les plus performantes et les plus adaptées aux exigences actuelles. \n\nL’objectif de notre société est de donner entière satisfaction à notre clientèle, dans le respect d’un cahier des charges arrêté d’un commun accord entre les parties, nous nous efforçons de combiner deux éléments qui nous semblent indissociables : du personnel efficace et des produits de qualité.\n\nNotre garantie est de nous occuper de tous types de prestations dans le respect des consignes et délais qui nous serons impartis, et ce partout au Maroc.', 11, 'nrs-groupe', 21, 403, 'nrs groupe', 3, 1, 'F-766d510', NULL, NULL, NULL, NULL),
(767, 144, 1, 'separator', 'M.', '000231019000072', '0522673400', 'http://www.separator-maroc.ma', 'Spécialiste dans l’aménagement d’espaces depuis 1999, le groupe SEPARATOR a développé une expertise authentique de Second Œuvre à travers un savoir-faire qui se perfectionne de jour en jour depuis 20 ans d’existence.\nNos Métiers :\nCLOISONS - RAYONNAGE - MINUISIER (ALUMINIUM ET BOIS) - FACADIER', 11, 'separator', 3, 90, 'separator', 3, 1, 'F-767b8e1', NULL, NULL, NULL, NULL),
(768, NULL, NULL, 'SERVICE POTECH', 'M.', NULL, NULL, NULL, NULL, NULL, 'service-potech', 0, 0, 'service potech', 1, 0, NULL, NULL, NULL, NULL, NULL),
(769, 220, 118, 'KM KUMSAN ', 'M.', NULL, '+902165930400', 'https://www.kumsan.com.tr/', 'KM KUMSAN CRANE SYSTEMS a été créée en 1973 en Turquie, et se dispose aujourd’hui comme leader industriel majeur sur le secteur des systèmes et équipements de manutention, en termes de conception, de fabrication, ainsi du service après-vente.\n\nSuite à notre implication dans plusieurs projets au niveau international, les activités d\'exportation de notre société ont augmenté progressivement et devraient représenter 90% de notre chiffre d\'affaires en 2020, et afin de répondre à la hausse de demande et de développer nos activités, nous avons ouvert un bureau de vente en Allemagne, et un bureau d\'études techniques et d\'ingénierie en Pologne, et nous comptons ouvrir une nouvelle facilité de 24 000 m² d\'ici la fin de 2020 à Kocaeli, en Turquie. \n\nKM KUMSAN CRANE SYSTEMS fabrique:\n-Palan électrique \n-Ponts roulants mono poutre et bipoutres (EOT)\n-Grues portiques\n-Grues potences (JIB)\n-Grues / ponts anti explosion \n-Grues / ponts spéciaux sur mesure\n-Chariots de transport\n-Portiques sur pneus (RTG)\n', 1, 'km-kumsan', 0, 57, 'km kumsan ', 3, 1, 'F-769f4ea', NULL, NULL, NULL, NULL),
(770, 144, 7, 'AFRICA COMPONENTS', 'M.', '002304129000049', '0664050447', 'http://www.africa-components.c', 'Nous sommes une société d\'ingénierie, nous sommes implantés à CASABLANCA et TANGER \n\n AFRICA COMPONENTS fournit une large gamme de produits industriels de différentes technologies (mécanique, électrique, pneumatique, hydraulique, électronique, automatisme, lubrification…). \n\nQue ce soit un article standard de commerce ou un article sur plan, nous pouvons vous garantir les meilleurs délais.\n\nNous proposons également des équivalents pour les articles obsolètes et plus fabriqués.\n\nNous commercialisons les marques les plus fiables du marché (Siemens, Schneider Electric, ABB, Allen Bradley, Sick, IFM, Honeywell, Zebra, Omron, SMC, Festo, Parker, Legris, Legrand, Pilz, Eaton…)\n\nNous avons un rapport délai / prix très compétitif \n\nJe reste à votre disposition pour toute information complémentaire \n', 11, 'africa-components', 4, 154, 'africa components', 3, 1, 'F-7703c3b', NULL, NULL, NULL, NULL),
