(858, 75, 89, 'S3D engineering ', 'M.', NULL, '+33525320926', 'https://www.s3dengineering.net', 'Réseau National de Scan 3D bâtiment\nVotre partenaire de confiance pour la numérisation 3D de vos bâtiments et installations industrielles, certifié ISO 9001 et offrant une garantie décennale. Choisissez le scan 3D bâtiment pour bénéficier de solutions innovantes et obtenir vos jumeaux numériques et BIM grâce au releve 3D !', 1, 's3d-engineering', 0, 43, 's3d engineering ', 3, 1, 'F-8589430', 'Bordeaux ', NULL, NULL, NULL),
(859, 75, 121, 'S3D ENGINEERING 33', 'M.', NULL, '+33619416160', 'https://www.s3dengineering.net', 'S3D ENGINEERING effectue des relevés et de la numérisation 3D, dans le bâtiment et l\'industrie, dont des plans 2D et 3D, des jumeaux numériques, de la détection de réseaux souterrains, de la modélisation et de la visualisation 3D.\nNous faisons partie d\'un réseau national certifié ISO 9001 - 2015 qui totalise 15 ans d\'expérience en France et à l\'international.\nDe grands groupes nous font déjà confiance : EDF, Dalkia, Technip, Marlier contrôles, Desautel, Legendre, Egis, Airbus...', 1, 's3d-engineering-33', 1, 43, 's3d engineering 33', 3, 1, 'F-8599035', NULL, NULL, NULL, NULL),
