(66, 2, 3, 765, NULL, '41022', 'Hongda Tea Co., experienced factory for more than 30 years,\nLocated in central China, a traditional green tea region,\nproduces Chunmee 41022/4011/9371:\n- Leaves selected from our mountain fields, processed in our factory and loaded into containers\n- Taste/aroma/color/foam... stable quality control for each production batch\n- Strengthens the competitiveness of your tea brand\n- specially for North and West Africa : Morocco, Algeria, Libya, Niger, Mali, Mauritania, Sénégal, ...\n\nContact: Mr. HAN\nTel/WA: +86 173 5282 0448\nhan@hndtea.com / www.hndtea.com', 0, 0, 0, 1, '2025-06-10 08:15:28', NULL, 454, 155, 'China manufacturer for Chunmee tea 41022 ', 2, '2025-08-13 12:57:59', 44, 'china-manufacturer-for-chunmee-tea-41022', 0, 'china manufacturer for chunmee tea 41022 ', 117, 1, NULL, NULL, NULL),
(67, 1, 140, 1099, NULL, 'PAL00023', 'Palettes en bois 1200*1000', 0, 0, 0, 1, '2025-06-12 11:14:42', NULL, 555, 147, 'Palettes en bois 1200*1000', 11, '2025-06-16 12:32:54', 144, 'palettes-en-bois-1200-1000', 0, 'palettes en bois 1200*1000', 1, 1, NULL, NULL, NULL),
(68, 1, 139, 1099, NULL, 'PAL00025', 'Palettes en bois EURO (EPAL) 1200*800', 0, 0, 0, 1, '2025-06-12 11:16:09', NULL, 554, 146, 'Palettes en bois EURO (EPAL) 1200*800', 11, '2025-06-16 12:32:43', 144, 'palettes-en-bois-euro-epal-1200-800', 0, 'palettes en bois euro (epal) 1200*800', 1, 1, NULL, NULL, NULL),
(69, 5, 17, 1107, NULL, 'H&B ', 'Article EPI et Vêtements de travail ', 0, 0, 0, 1, '2025-06-17 18:25:11', NULL, 558, 156, 'EPI et Vêtements de travail ', 11, '2025-08-13 13:00:46', 144, 'epi-et-vetements-de-travail', 0, 'epi et vêtements de travail ', 1, 1, NULL, NULL, NULL),
(70, 26, 74, 1214, NULL, 'Stratégie markéting', 'DIGITAL STRATEGY\n⦁ Community Management Stratégique : Nos community managers, toujours à l\'affût des dernières tendances, optimisent et développent votre écosystème digital. De la création de contenu à sa diffusion, en passant par le média planning et la modération, nous gérons l’ensemble du processus pour offrir une véritable expérience de marque.\n⦁ Création et Diffusion de Contenus Premium : Nous donnons vie à votre vision en mettant en avant vos valeurs et votre expertise. De la conception du storyboard à la production de contenus live multicanaux, nous vous conseillons sur les formats les plus adaptés à vos enjeux.\n⦁ Accédez à notre studio et à un matériel de pointe pour des shootings photo et vidéo de qualité professionnelle, garantissant un rendu optimal sur tous vos supports.', 0, 0, 0, 1, '2025-06-20 09:41:59', NULL, 325, 154, 'DIGITAL STRATEGY', 11, '2025-06-20 10:48:26', 144, 'digital-strategy', 0, 'digital strategy', 1, 1, NULL, NULL, NULL),
(71, 2, 2, 765, NULL, '41022', 'Hongda Tea est Usine expert du thé du désert.  \nFocalisé sur Chunmee 41022 Haut de gamme,\nSélection de thé du printemps 100% naturel,  \nculture, traitement, export par l’usine, sans intermédiare,\nContact: M. HAN\nTel/WA: +86 173 5282 0448\nEmail: han@hndtea.com\nwww.hndtea.com\n', 0, 0, 0, 1, '2025-09-24 09:25:01', NULL, 509, NULL, 'Usine de thé du désert haute qualité', 2, '2025-09-24 12:34:54', 44, 'usine-de-the-du-desert-haute-qualite', 0, 'usine de thé du désert haute qualité', 117, 1, NULL, NULL, NULL),
(72, 2, 2, 765, NULL, '41022*4011*9371', 'Expérimentée de 30 ans,\nHongda Tea est focalisée sur la production et export du Thé vert de Chine, en mettant en priorité : \n✅ Qualité stable & traçabilité : conformité stricte à l’échantillon validé\n✅ Logistique maîtrisée : documents complets, dédouanement facile\n✅ Partenariat durable : collaboration gagnant-gagnant, au lieu de vendre un container seulement\n🔹 La réputation de l’usine n’a pas de prix !\n\nContact: M. HAN\nTel/WA: +86 173 5282 0448\nhan@hndtea.com  /  www.hndtea.com\n', 0, 0, 0, 0, '2025-11-25 04:40:04', NULL, 509, NULL, 'Usine de Thé Vert Chinois – Après-Vente Fiable et Professionnel', 2, NULL, 44, 'usine-de-the-vert-chinois-apres-vente-fiable-et-professionnel', 0, 'usine de thé vert chinois – après-vente fiable et professionnel', 117, 1, NULL, NULL, NULL),
(73, 3, 13, 2762, 27, 'A cupiditate saepe m', 'Dolor laboris aut en', 77, 0, 0, 0, '2026-01-16 01:09:30', NULL, NULL, NULL, 'Veritatis amet aliq', 2, NULL, 144, 'veritatis-amet-aliq', 0, 'veritatis amet aliq', 2, 1, NULL, NULL, NULL);
